@router.post("/apply", status_code=200)
async def apply_referral_code(
    request: ApplyReferralRequest,
    current_user = Depends(get_current_user)
):
    """Apply a referral code during signup - awards bonuses to both parties"""
    db = get_db()

    # Validate code format
    code = request.referral_code.upper()
    if not code.startswith("IH-"):
        raise HTTPException(status_code=400, detail="Invalid referral code format")

    # Determine expected prefix
    expected_prefix = "IH-V" if request.referral_type == ReferralType.VENDOR else "IH-C"
    if not code.startswith(expected_prefix):
        raise HTTPException(
            status_code=400, 
            detail=f"This code is for {'vendors' if request.referral_type == ReferralType.CUSTOMER else 'customers'}"
        )

    # Validate code exists in database
    code_record = await db.referral_codes.find_one({
        "code": code,
        "referral_type": request.referral_type.value,
        "is_active": True
    })

    if not code_record:
        raise HTTPException(status_code=404, detail="Invalid or expired referral code")

    # Check if code is expired
    if code_record.get("expires_at") and code_record["expires_at"] < datetime.utcnow():
        raise HTTPException(status_code=400, detail="This referral code has expired")

    # Prevent self-referral
    if code_record["user_id"] == str(current_user.id):
        raise HTTPException(status_code=400, detail="You cannot use your own referral code")

    # Check if user has already used a referral code of this type
    existing_referral = await db.referrals.find_one({
        "referee_id": str(current_user.id),
        "referral_type": request.referral_type.value,
        "status": {"$in": [ReferralStatus.COMPLETED.value, ReferralStatus.PENDING.value]}
    })

    if existing_referral:
        raise HTTPException(
            status_code=400, 
            detail=f"You have already used a {request.referral_type.value} referral code"
        )

    # Check if user has already been referred by this person
    duplicate_referral = await db.referrals.find_one({
        "referrer_id": code_record["user_id"],
        "referee_id": str(current_user.id),
        "referral_type": request.referral_type.value
    })

    if duplicate_referral:
        raise HTTPException(status_code=400, detail="You have already been referred by this user")

    rewards = ReferralReward(referral_type=request.referral_type)

    # Create referral record in database
    referral = Referral(
        referrer_id=code_record["user_id"],
        referee_id=str(current_user.id),
        referral_code=code,
        referral_type=request.referral_type,
        status=ReferralStatus.COMPLETED,  # Auto-complete for now
        completed_at=datetime.utcnow(),
        reward_applied=True,
        reward_details={}
    )

    await db.referrals.insert_one(referral.dict())

    if request.referral_type == ReferralType.VENDOR:
