@router.get("/customer/rewards", response_model=CustomerRewardsResponse)
async def get_customer_rewards(current_user = Depends(get_current_user)):
    """Get detailed customer rewards, tier status, and benefits"""
    db = get_db()

    # Fetch from database
    account = await db.customer_reward_accounts.find_one({
        "customer_id": str(current_user.id)
    })

    if not account:
        # Get referral code if exists
        code_record = await db.referral_codes.find_one({
            "user_id": str(current_user.id),
            "referral_type": ReferralType.CUSTOMER.value
        })
        referral_code = code_record["code"] if code_record else "IH-C-NONE"

        return CustomerRewardsResponse(
            referral_code=referral_code,
            tier="bronze",
            hashi_coins_balance=0,
            total_referrals=0,
            free_delivery_credits=0,
            discount_credits=0.0,
            tier_progress={
                "current_tier": "Bronze",
                "referrals_to_next_tier": 1,
                "next_tier": "Silver"
            },
            tier_benefits=CustomerRewardAccount.get_tier_benefits(CustomerTier.BRONZE)
        )

    # Calculate tier progress
    completed = account.get("completed_referrals", 0)
    current_tier = account.get("tier", "bronze")

    tier_thresholds = {
        "bronze": {"min": 1, "next": "silver", "next_min": 6},
        "silver": {"min": 6, "next": "gold", "next_min": 16},
        "gold": {"min": 16, "next": "platinum", "next_min": 51},
        "platinum": {"min": 51, "next": None, "next_min": None}
    }

    tier_info = tier_thresholds.get(current_tier, tier_thresholds["bronze"])
    next_tier = tier_info["next"]
    referrals_to_next = max(0, tier_info["next_min"] - completed) if tier_info["next_min"] else 0

    return CustomerRewardsResponse(
        referral_code=account.get("referral_code", "IH-C-NONE"),
        tier=current_tier,
        hashi_coins_balance=account.get("hashi_coins_balance", 0),
        total_referrals=account.get("total_referrals", 0),
        free_delivery_credits=account.get("free_delivery_credits", 0),
        discount_credits=account.get("discount_credits", 0.0),
        tier_progress={
            "current_tier": current_tier.capitalize(),
            "referrals_to_next_tier": referrals_to_next,
            "next_tier": next_tier.capitalize() if next_tier else None,
            "completed_referrals": completed
        },
        tier_benefits=CustomerRewardAccount.get_tier_benefits(CustomerTier(current_tier))
    )


