async def handle_order_accepted(rider_id: str, order_id: str):
    """Handle when a rider accepts an order"""
    orders_col = get_collection("orders")

    # Update order
    await orders_col.update_one(
        {"id": order_id},
        {
            "$set": {
                "rider_id": rider_id,
                "status": "confirmed",
                "confirmed_at": datetime.utcnow()
            },
            "$push": {
                "status_history": {
                    "status": "confirmed",
                    "timestamp": datetime.utcnow().isoformat(),
                    "actor": rider_id
                }
            }
        }
    )

    # Notify order room
    await manager.broadcast_to_room(
        RoomType.ORDER,
        order_id,
        {
            "type": WebSocketEventType.DRIVER_ASSIGNED,
            "order_id": order_id,
            "rider_id": rider_id,
            "timestamp": datetime.utcnow().isoformat()
        }
    )


async def handle_delivery_completed(rider_id: str, order_id: str):
    """Handle when a rider completes a delivery"""
    orders_col = get_collection("orders")

    # Update order
    await orders_col.update_one(
        {"id": order_id},
        {
            "$set": {
                "status": "delivered",
                "delivered_at": datetime.utcnow()
            },
            "$push": {
                "status_history": {
                    "status": "delivered",
                    "timestamp": datetime.utcnow().isoformat(),
                    "actor": rider_id
                }
            }
        }
    )

    # Notify order room
    await manager.broadcast_to_room(
        RoomType.ORDER,
        order_id,
        {
            "type": WebSocketEventType.DELIVERY_COMPLETED,
            "order_id": order_id,
            "rider_id": rider_id,
            "timestamp": datetime.utcnow().isoformat()
        }
    )

    # Get order details to notify user
    order = await orders_col.find_one({"id": order_id})
    if order:
        await manager.send_to_user(
            order.get("buyer_id"),
            {
                "type": WebSocketEventType.DELIVERY_COMPLETED,
                "order_id": order_id,
                "message": "Your order has been delivered!",
                "timestamp": datetime.utcnow().isoformat()
            }
        )


