        {
            "type": WebSocketEventType.ORDER_STATUS_UPDATED,
            "order_id": order_id,
            "status": new_status,
            "timestamp": datetime.utcnow().isoformat()
        }
    )

    # Notify user
    order = await orders_col.find_one({"id": order_id})
    if order:
        await manager.send_to_user(
