@router.post("/admin/process-pending")
async def process_pending_referrals():
    """Process pending referrals and award bonuses (called by cron job)"""
    db = get_db()

    # Fetch all pending referrals
    pending_cursor = db.referrals.find({
        "status": ReferralStatus.PENDING.value,
        "referral_type": ReferralType.CUSTOMER.value
    })

    processed_count = 0
    awards_given = 0

    async for referral in pending_cursor:
        referee_id = referral["referee_id"]
        referrer_id = referral["referrer_id"]

        # Check if referee has completed required action (e.g., first order)
        # For now, we'll check if they have any orders
        order_count = await db.orders.count_documents({"buyer_id": referee_id})

        if order_count > 0:
            # Award bonuses to both parties
            rewards = ReferralReward(referral_type=ReferralType.CUSTOMER)

            # Update referrer's account
            referrer_account = await db.customer_reward_accounts.find_one({
                "customer_id": referrer_id
            })

            if referrer_account:
                new_balance = referrer_account.get("hashi_coins_balance", 0) + rewards.customer_referrer_coins

                await db.customer_reward_accounts.update_one(
                    {"customer_id": referrer_id},
                    {
                        "$inc": {
                            "hashi_coins_balance": rewards.customer_referrer_coins,
                            "total_coins_earned": rewards.customer_referrer_coins,
                            "completed_referrals": 1
                        },
                        "$set": {"updated_at": datetime.utcnow()}
                    }
                )

                # Create coin transaction
                txn = CoinTransaction(
                    customer_id=referrer_id,
                    amount=rewards.customer_referrer_coins,
                    transaction_type="referral_reward",
                    description=f"Referral completed for user {referee_id}",
                    related_referral_id=referral["id"],
                    balance_after=new_balance
                )
                await db.coin_transactions.insert_one(txn.dict())

                awards_given += 1

            # Update referral status
            await db.referrals.update_one(
                {"id": referral["id"]},
                {
                    "$set": {
                        "status": ReferralStatus.COMPLETED.value,
                        "completed_at": datetime.utcnow(),
                        "reward_applied": True
                    }
                }
            )

            processed_count += 1

    logger.info(f"Processed {processed_count} pending referrals, awarded {awards_given} bonuses")

    return {
        "message": "Pending referrals processed",
        "processed_count": processed_count,
        "awards_given": awards_given
    }


