@router.get("/referral-link", response_model=ReferralLinkResponse)
async def get_referral_link(current_user = Depends(get_current_user)):
    """Get your unique referral link to share with friends"""
    db = get_db()

    # Fetch or create referral code from database
    code_record = await db.referral_codes.find_one({
        "user_id": str(current_user.id),
        "referral_type": ReferralType.CUSTOMER.value
    })

    if code_record:
        code = code_record["code"]
    else:
        # Generate new code
        max_attempts = 10
        for _ in range(max_attempts):
            code = ReferralCode.generate_code("IH-C")
            existing = await db.referral_codes.find_one({"code": code})
            if not existing:
                break
        else:
            raise HTTPException(status_code=500, detail="Failed to generate unique referral code")

        # Store in database
        referral_code = ReferralCode(
            user_id=str(current_user.id),
            code=code,
            referral_type=ReferralType.CUSTOMER
        )
        await db.referral_codes.insert_one(referral_code.dict())

        # Create reward account if not exists
        existing_account = await db.customer_reward_accounts.find_one({
            "customer_id": str(current_user.id)
        })
        if not existing_account:
            reward_account = CustomerRewardAccount(
                customer_id=str(current_user.id),
                referral_code=code
            )
            await db.customer_reward_accounts.insert_one(reward_account.dict())
        else:
            # Update referral code
            await db.customer_reward_accounts.update_one(
                {"customer_id": str(current_user.id)},
                {"$set": {"referral_code": code, "updated_at": datetime.utcnow()}}
            )

    base_url = settings.FRONTEND_URL or "https://ihhashi.app"

    return ReferralLinkResponse(
        referral_code=code,
        share_link=f"{base_url}/signup?ref={code}",
        message="Share this link with friends! You BOTH get Hashi Coins when they sign up!",
        coins_for_referrer=CoinValues.REFERRAL_BONUS_REFERRER,
        coins_for_friend=CoinValues.REFERRAL_BONUS_REFEREE

