 69	        onConnect: () => {
 70	          setStatus(ConnectionStatus.CONNECTED);
 71	          wsOptions.onConnect?.();
 72	        },
 73	        onDisconnect: () => {
 74	          setStatus(ConnectionStatus.DISCONNECTED);
 75	          wsOptions.onDisconnect?.();
 76	        },
 77	        onError: (err) => {
 78	          setStatus(ConnectionStatus.ERROR);
 79	          setError(err instanceof Error ? err : new Error('WebSocket error'));
 80	          wsOptions.onError?.(err);
 81	        },
 82	        onMessage: wsOptions.onMessage,
 83	      });
 84	    } catch (err) {
 85	      setError(err instanceof Error ? err : new Error('Failed to connect'));
 86	      throw err;
 87	    }
 88	  }, [endpoint, wsOptions]);
