103	  const unsubscribe = useCallback((roomType: RoomType, roomId: string) => {
104	    websocketService.unsubscribe(roomType, roomId);
105	  }, []);
106	
107	  const on = useCallback((type: string, handler: (event: WebSocketEvent) => void): (() => void) => {
108	    handlersRef.current.push({ type, handler });
109	    return websocketService.on(type, handler);
110	  }, []);
111	
112	  const off = useCallback((type: string, handler: (event: WebSocketEvent) => void) => {
113	    handlersRef.current = handlersRef.current.filter(
114	      (h) => h.type !== type || h.handler !== handler
115	    );
116	    websocketService.off(type, handler);
117	  }, []);
118	
119	  // Auto-connect on mount
120	  useEffect(() => {
121	    if (autoConnect) {
122	      connect();
123	    }
124	
125	    // Cleanup on unmount
126	    return () => {
127	      // Only disconnect if we're the only component using the service
128	      // This is a simplification - in production, you'd want reference counting
129	      handlersRef.current.forEach(({ type, handler }) => {
130	        websocketService.off(type, handler);
131	      });
132	    };
133	  }, [autoConnect, connect]);
134	
135	  return {
136	    status,
137	    isConnected,
138	    isConnecting,
139	    error,
140	    connect,
141	    disconnect,
142	    send,
143	    subscribe,
