196	        switch (event.type) {
197	          case WebSocketEventType.CONNECTED:
198	            setIsConnected(true);
199	            setIsConnecting(false);
200	            if (event.order) {
201	              setOrder((prev) => ({ ...prev, ...event.order } as OrderWithRealtime));
202	            }
203	            break;
204	
205	          case WebSocketEventType.ORDER_STATUS_UPDATED:
206	            setOrder((prev) => 
207	              prev ? { ...prev, status: event.status, status_history: event.status_history || [] } : null
208	            );
