{"path": "frontend/src/pages/RewardsPage.tsx", "content": "import { useState, useEffect } from 'react';
import { useAuth } from '../hooks/useAuth';
import { api } from '../services/api';
import { 
  Gift, 
  Share2, 
  Coins, 
  TrendingUp, 
  Award,
  Copy,
  Check,
  ChevronRight,
  Medal,
  Crown,
  Diamond
} from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';

interface TierInfo {
  tier: string;
  tier_name: string;
  tier_icon: string;
  tier_color: string;
  hashi_coins_balance: number;
  total_referrals: number;
  referral_code: string;
  free_delivery_credits: number;
  discount_credits: number;
  tier_progress: {
    bronze: { min: number; achieved: boolean };
    silver: { min: number; achieved: boolean };
    gold: { min: number; achieved: boolean };
    platinum: { min: number; achieved: boolean };
  };
  next_tier: string | null;
  referrals_to_next_tier: number;
  tier_benefits: {
    name: string;
    discount_percent: number;
    free_deliveries_per_month: number;
    support_level: string;
    exclusive_offers: boolean;
    early_access: boolean;
    icon: string;
    color: string;
  };
  referral_history: any[];
  coin_history: any[];
}

interface TierConfig {
  tier: string;
  name: string;
  icon: string;
  color: string;
  discount_percent: number;
  free_deliveries_per_month: number;
  support_level: string;
  exclusive_offers: boolean;
  early_access: boolean;
  referral_range: { min: number; max: number | string };
}

export function RewardsPage() {
  const { user } = useAuth();
  const [dashboard, setDashboard] = useState<TierInfo | null>(null);
  const [tiers, setTiers] = useState<TierConfig[]>([]);
  const [loading, setLoading] = useState(true);
  const [copied, setCopied] = useState(false);
  const [activeTab, setActiveTab] = useState<'overview' | 'referrals' | 'history'>('overview');
  const [redeeming, setRedeeming] = useState<string | null>(null);
  const [redeemMessage, setRedeemMessage] = useState<string>('');

  useEffect(() => {
    loadDashboard();
    loadTiers();
  }, []);

  const loadDashboard = async () => {
    try {
      const response = await api.get('/api/v1/customer-rewards/dashboard');
      setDashboard(response.data);
    } catch (error) {
      console.error('Failed to load dashboard:', error);
    } finally {
      setLoading(false);
    }
  };

  const loadTiers = async () => {
    try {
      const response = await api.get('/api/v1/customer-rewards/tiers');
      setTiers(response.data.tiers);
    } catch (error) {
      console.error('Failed to load tiers:', error);
    }
  };

  const copyReferralCode = () => {
    if (dashboard?.referral_code) {
      navigator.clipboard.writeText(dashboard.referral_code);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    }
  };

  const shareReferral = async () => {
    const shareText = `Join me on iHhashi and get ${dashboard?.referral_code ? '25 Hashi Coins' : 'rewards'}! Use my code: ${dashboard?.referral_code || 'IH-C-XXXXXX'}. Download the app: https://ihhashi.co.za`;

    if (navigator.share) {
      try {
        await navigator.share({
          title: 'Join iHhashi',
          text: shareText,
          url: `https://ihhashi.co.za/signup?ref=${dashboard?.referral_code || ''}`,
        });
      } catch (error) {
        console.log('Share cancelled');
      }
    } else {
      navigator.clipboard.writeText(shareText);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    }
  };

  const redeemReward = async (type: 'free-delivery' | 'discount-15' | 'discount-30') => {
    setRedeeming(type);
    try {
      let response;
      if (type === 'free-delivery') {
        response = await api.post('/api/v1/customer-rewards/redeem/free-delivery');
      } else {
        const amount = type === 'discount-15' ? 15 : 30;
        response = await api.post(`/api/v1/customer-rewards/redeem/discount/${amount}`);
      }

      if (response.data.success) {
        setRedeemMessage(response.data.message);
        loadDashboard(); // Refresh dashboard
      } else {
